#!/usr/bin/env bash
# submit-risk-assessment.sh - Stage 250 automated risk assessment (garak-kfp)
# Submits a context-aware adversarial red-team evaluation (benchmark
# `intents`, provider `garak-kfp`) against the governed Nemotron model,
# judged/generated by gpt-4o-mini, orchestrated through the stage DSPA KFP
# pipeline server. Polls the EvalHub job to completion. This is an on-demand
# demo action, not part of every deploy.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
ROOT_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"

if [[ -f "$ROOT_DIR/.env" ]]; then
  set -a
  # shellcheck source=/dev/null
  source "$ROOT_DIR/.env"
  set +a
fi

if [[ -z "${RHOAI_EXPECTED_API_SERVER:-}" ]]; then
  echo "ERROR: RHOAI_EXPECTED_API_SERVER is not set." >&2
  exit 1
fi
ACTUAL_SERVER=$(oc whoami --show-server 2>/dev/null || true)
if [[ "$ACTUAL_SERVER" != *"$RHOAI_EXPECTED_API_SERVER"* ]]; then
  echo "ERROR: Active cluster ($ACTUAL_SERVER) does not match RHOAI_EXPECTED_API_SERVER." >&2
  exit 1
fi
for cmd in oc jq curl; do
  command -v "$cmd" >/dev/null 2>&1 || { echo "ERROR: required command not found: $cmd" >&2; exit 1; }
done

EVAL_NS="${RHOAI_STAGE250_NAMESPACE:-model-evaluation}"
MODEL_TOKEN_SECRET="${RHOAI_STAGE250_MODEL_TOKEN_SECRET:-model-evaluation-model-token}"
TARGET_MODEL="${RHOAI_STAGE250_RISK_TARGET_MODEL:-nemotron-3-nano-30b-a3b}"
JUDGE_MODEL="${RHOAI_STAGE250_RISK_JUDGE_MODEL:-gpt-4o-mini}"
DSPA_NAME="${RHOAI_STAGE250_DSPA_NAME:-dspa-model-evaluation}"
PROXY="http://maas-internal-proxy.${EVAL_NS}.svc.cluster.local:8080/models-as-a-service"
KFP_ENDPOINT="https://ds-pipeline-${DSPA_NAME}.${EVAL_NS}.svc.cluster.local:8443"
JOB_NAME="${RHOAI_STAGE250_RISK_JOB_NAME:-nemotron-risk-$(date -u +%Y%m%d%H%M%S)}"
POLL_TIMEOUT="${RHOAI_STAGE250_RISK_TIMEOUT:-3600}"

# Guardrails: the model API key Secret must carry an api-key key.
if ! oc get secret "$MODEL_TOKEN_SECRET" -n "$EVAL_NS" -o jsonpath='{.data.api-key}' \
  --insecure-skip-tls-verify=true 2>/dev/null | grep -q .; then
  echo "ERROR: Secret ${MODEL_TOKEN_SECRET} in ${EVAL_NS} has no api-key key. Run deploy.sh first." >&2
  exit 1
fi

# EvalHub REST is authenticated; use the caller's OpenShift token and the
# tenant header. Query in-cluster from the EvalHub pod so TLS/DNS are simple.
EVALHUB_POD=$(oc get pods -n "$EVAL_NS" --insecure-skip-tls-verify=true 2>/dev/null \
  | grep '^evalhub-' | awk '{print $1}' | head -1)
if [[ -z "$EVALHUB_POD" ]]; then
  echo "ERROR: no running evalhub pod in ${EVAL_NS}." >&2
  exit 1
fi
TOKEN=$(oc whoami -t --insecure-skip-tls-verify=true)

request=$(cat <<JSON
{
  "name": "${JOB_NAME}",
  "model": {
    "url": "${PROXY}/${TARGET_MODEL}/v1",
    "name": "${TARGET_MODEL}",
    "auth": { "secret_ref": "${MODEL_TOKEN_SECRET}" }
  },
  "experiment": { "name": "${JOB_NAME}" },
  "benchmarks": [
    {
      "id": "intents",
      "provider_id": "garak-kfp",
      "parameters": {
        "kfp_config": {
          "endpoint": "${KFP_ENDPOINT}",
          "namespace": "${EVAL_NS}",
          "s3_secret_name": "${RHOAI_STAGE250_S3_SECRET:-model-evaluation-s3}",
          "verify_ssl": false
        },
        "intents_models": {
          "judge": { "url": "${PROXY}/${JUDGE_MODEL}/v1", "name": "${JUDGE_MODEL}" },
          "sdg":   { "url": "${PROXY}/${JUDGE_MODEL}/v1", "name": "hosted_vllm/${JUDGE_MODEL}" }
        }
      }
    }
  ]
}
JSON
)

echo "── Submitting garak-kfp risk assessment ──"
echo "  target: ${TARGET_MODEL} | judge/sdg: ${JUDGE_MODEL}"
echo "  kfp: ${KFP_ENDPOINT}"

resp=$(oc exec -n "$EVAL_NS" "$EVALHUB_POD" --insecure-skip-tls-verify=true -- \
  curl -sk --max-time 60 -X POST https://localhost:8443/api/v1/evaluations/jobs \
  -H "Authorization: Bearer ${TOKEN}" \
  -H "X-Tenant: ${EVAL_NS}" \
  -H "Content-Type: application/json" \
  -d "$request" 2>/dev/null || true)

job_id=$(jq -r '.id // .resource.id // empty' <<<"$resp" 2>/dev/null || true)
if [[ -z "$job_id" ]]; then
  echo "ERROR: submission failed. Response:" >&2
  echo "$resp" | head -c 600 >&2; echo >&2
  exit 1
fi
echo "✓ Submitted evaluation job ${job_id}"

echo "── Polling job status (timeout ${POLL_TIMEOUT}s) ──"
elapsed=0
while (( elapsed < POLL_TIMEOUT )); do
  status=$(oc exec -n "$EVAL_NS" "$EVALHUB_POD" --insecure-skip-tls-verify=true -- \
    curl -sk --max-time 30 -H "Authorization: Bearer ${TOKEN}" -H "X-Tenant: ${EVAL_NS}" \
    "https://localhost:8443/api/v1/evaluations/jobs/${job_id}" 2>/dev/null || true)
  state=$(jq -r '.status // .resource.status // .state // empty' <<<"$status" 2>/dev/null || true)
  echo "  [$elapsed s] state=${state:-unknown}"
  case "$state" in
    completed|Completed) echo "✓ Risk assessment completed"; echo "$status" | jq '.' 2>/dev/null | head -60; exit 0 ;;
    failed|Failed|cancelled|Cancelled) echo "✗ Risk assessment ${state}"; echo "$status" | jq '.' 2>/dev/null | head -40; exit 1 ;;
  esac
  sleep 30
  (( elapsed += 30 ))
done
echo "! Risk assessment did not complete within ${POLL_TIMEOUT}s; check the KFP run in the dashboard." >&2
exit 1
